import React from "react";

function ListofIndianPlayers(props) {
    return (
        <div>
            <ul>
                {props.IndianPlayers.map((player, index) => (
                    <li key={index}>
                        Mr. {player}
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default ListofIndianPlayers;
